File Storage Service:

```hcl
resource "oci_file_storage_file_system" "shared" {
  compartment_id      = var.compartment_ocid
  availability_domain = "QnsQ:US-ASHBURN-AD-1"
  display_name        = "shared-fs"
}

resource "oci_file_storage_mount_target" "mt" {
  compartment_id      = var.compartment_ocid
  availability_domain = "QnsQ:US-ASHBURN-AD-1"
  subnet_id           = oci_core_subnet.private.id
}

resource "oci_file_storage_export" "export" {
  export_set_id  = oci_file_storage_mount_target.mt.export_set_id
  file_system_id = oci_file_storage_file_system.shared.id
  path           = "/shared"
  export_options {
    source  = "10.0.0.0/16"
    access  = "READ_WRITE"
  }
}
```

Monte nas instâncias: echo 'ip:/shared /mnt/shared nfs defaults 0 0' >> /etc/fstab

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Backup policies:

```hcl
resource "oci_core_volume_backup_policy" "daily" {
  compartment_id = var.compartment_ocid
  schedules {
    period            = "ONE_DAY"
    retention_seconds = 2592000  # 30 dias
    offset_type       = "HOUR"
    offset_number     = 2
    backup_type       = "INCREMENTAL"
  }
  schedules {
    period            = "ONE_WEEK"
    retention_seconds = 7776000  # 90 dias
    backup_type       = "FULL"
  }
}

resource "oci_core_volume_backup_policy_assignment" "assign" {
  asset_id  = oci_core_volume.data.id
  policy_id = oci_core_volume_backup_policy.daily.id
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Encryption com OCI Vault (BYOK):

```hcl
resource "oci_kms_vault" "vault" {
  compartment_id = var.compartment_ocid
  display_name   = "storage-vault"
  vault_type     = "DEFAULT"
}

resource "oci_kms_key" "key" {
  compartment_id      = var.compartment_ocid
  display_name        = "block-volume-key"
  management_endpoint = oci_kms_vault.vault.management_endpoint
  key_shape { algorithm = "AES"; length = 32 }
}

resource "oci_core_volume" "encrypted" {
  compartment_id      = var.compartment_ocid
  availability_domain = "QnsQ:US-ASHBURN-AD-1"
  size_in_gbs         = 500
  kms_key_id          = oci_kms_key.key.id
}
```

Policy: Allow service blockstorage to use vaults/keys

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs
